import{c as r,Q as t,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-23","description":"","frontmatter":{"title":"The Decoder — 2026-05-23","date":"2026-05-23T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-23-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-23-the-decoder.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-23-the-decoder.md"};function i(s,e,d,p,c,l){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🔓-the-decoder-—-2026-05-23" tabindex="-1">🔓 The Decoder — 2026-05-23 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-23" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-23&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="cloudflare-ceo-prince-says-builders-and-sellers-are-safe-but-ai-is-coming-for-the-measurers" tabindex="-1"><a href="https://the-decoder.com/cloudflare-ceo-prince-says-builders-and-sellers-are-safe-but-ai-is-coming-for-the-measurers/" target="_blank" rel="noreferrer">Cloudflare CEO Prince says builders and sellers are safe but AI is coming for the measurers</a> <a class="header-anchor" href="#cloudflare-ceo-prince-says-builders-and-sellers-are-safe-but-ai-is-coming-for-the-measurers" aria-label="Permalink to &quot;[Cloudflare CEO Prince says builders and sellers are safe but AI is coming for the measurers](https://the-decoder.com/cloudflare-ceo-prince-says-builders-and-sellers-are-safe-but-ai-is-coming-for-the-measurers/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-22</em></p><p>Cloudflare CEO Matthew Prince laid off more than 20 percent of the workforce despite record revenue, claiming AI is replacing middle management and compliance roles. But the company offers no hard evidence for that. Falling margins and a headcount that surged 40 percent in two years point to a classic efficiency program wrapped in AI branding.</p><p>The article <a href="https://the-decoder.com/cloudflare-ceo-prince-says-builders-and-sellers-are-safe-but-ai-is-coming-for-the-measurers/" target="_blank" rel="noreferrer">Cloudflare CEO Prince says builders and sellers are safe but AI is coming for the measurers</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="openai-launches-a-chatgpt-powerpoint-plugin-and-warns-it-might-accidentally-delete-your-content" tabindex="-1"><a href="https://the-decoder.com/openai-launches-a-chatgpt-powerpoint-plugin-and-warns-it-might-accidentally-delete-your-content/" target="_blank" rel="noreferrer">OpenAI launches a ChatGPT Powerpoint plugin and warns it might accidentally delete your content</a> <a class="header-anchor" href="#openai-launches-a-chatgpt-powerpoint-plugin-and-warns-it-might-accidentally-delete-your-content" aria-label="Permalink to &quot;[OpenAI launches a ChatGPT Powerpoint plugin and warns it might accidentally delete your content](https://the-decoder.com/openai-launches-a-chatgpt-powerpoint-plugin-and-warns-it-might-accidentally-delete-your-content/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-22</em></p><p>OpenAI brings ChatGPT directly into PowerPoint. A new beta plugin creates presentations from notes, documents, or images and edits existing slides. The add-in is available worldwide across all tiers. OpenAI recommends saving important decks before using it.</p><p>The article <a href="https://the-decoder.com/openai-launches-a-chatgpt-powerpoint-plugin-and-warns-it-might-accidentally-delete-your-content/" target="_blank" rel="noreferrer">OpenAI launches a ChatGPT Powerpoint plugin and warns it might accidentally delete your content</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="deepseek-reportedly-prioritizes-agi-research-over-quick-profits-despite-billions-in-funding" tabindex="-1"><a href="https://the-decoder.com/deepseek-reportedly-prioritizes-agi-research-over-quick-profits-despite-billions-in-funding/" target="_blank" rel="noreferrer">Deepseek reportedly prioritizes AGI research over quick profits despite billions in funding</a> <a class="header-anchor" href="#deepseek-reportedly-prioritizes-agi-research-over-quick-profits-despite-billions-in-funding" aria-label="Permalink to &quot;[Deepseek reportedly prioritizes AGI research over quick profits despite billions in funding](https://the-decoder.com/deepseek-reportedly-prioritizes-agi-research-over-quick-profits-despite-billions-in-funding/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-22</em></p><p>Deepseek is about to raise around $10 billion, which would value the Chinese AI startup at roughly $45 billion. Founder Liang Wenfeng is telling investors he&#39;s putting AGI research ahead of short-term profits.</p><p>The article <a href="https://the-decoder.com/deepseek-reportedly-prioritizes-agi-research-over-quick-profits-despite-billions-in-funding/" target="_blank" rel="noreferrer">Deepseek reportedly prioritizes AGI research over quick profits despite billions in funding</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="openai-appshots-turn-any-mac-window-into-context-for-codex" tabindex="-1"><a href="https://the-decoder.com/openai-appshots-turn-any-mac-window-into-context-for-codex/" target="_blank" rel="noreferrer">OpenAI Appshots turn any Mac window into context for Codex</a> <a class="header-anchor" href="#openai-appshots-turn-any-mac-window-into-context-for-codex" aria-label="Permalink to &quot;[OpenAI Appshots turn any Mac window into context for Codex](https://the-decoder.com/openai-appshots-turn-any-mac-window-into-context-for-codex/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-22</em></p><p>With the new Codex feature Appshots, Mac users can send the contents of any app window to OpenAI&#39;s coding assistant Codex at the press of a button, giving it the context it needs for a task.</p><p>The article <a href="https://the-decoder.com/openai-appshots-turn-any-mac-window-into-context-for-codex/" target="_blank" rel="noreferrer">OpenAI Appshots turn any Mac window into context for Codex</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="openai-burned-through-1-22-per-dollar-earned-even-after-stripping-out-stock-based-compensation" tabindex="-1"><a href="https://the-decoder.com/openai-burned-through-1-22-per-dollar-earned-even-after-stripping-out-stock-based-compensation/" target="_blank" rel="noreferrer">OpenAI burned through $1.22 per dollar earned even after stripping out stock-based compensation</a> <a class="header-anchor" href="#openai-burned-through-1-22-per-dollar-earned-even-after-stripping-out-stock-based-compensation" aria-label="Permalink to &quot;[OpenAI burned through $1.22 per dollar earned even after stripping out stock-based compensation](https://the-decoder.com/openai-burned-through-1-22-per-dollar-earned-even-after-stripping-out-stock-based-compensation/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-22</em></p><p>OpenAI pulled in about $5.7 billion in Q1 2026 revenue but still lost $1.22 for every dollar earned, putting its adjusted operating margin at minus 122 percent.</p><p>The article <a href="https://the-decoder.com/openai-burned-through-1-22-per-dollar-earned-even-after-stripping-out-stock-based-compensation/" target="_blank" rel="noreferrer">OpenAI burned through $1.22 per dollar earned even after stripping out stock-based compensation</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const f=r(n,[["render",i]]);export{u as __pageData,f as default};
